def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--output", "-o", default="backend/data/players.json")
    args = parser.parse_args()

    for i, p in enumerate(PLAYERS, 1):
        p["id"] = i
        p["nbaId"] = i
        p["hasDetailedStats"] = True

    os.makedirs(os.path.dirname(args.output) or ".", exist_ok=True)
    with open(args.output, "w", encoding="utf-8") as f:
        json.dump(PLAYERS, f, ensure_ascii=False, indent=2)

    print(f"Generated {len(PLAYERS)} players with detailed stats")
    print(f"File: {args.output} ({os.path.getsize(args.output)} bytes)")

if __name__ == "__main__":
    main()
